module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

reg [15:0] areg, breg;
reg [31:0] yout_r;
reg [4:0] i;
reg done_r;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        i <= 0;
    end
    else if (start && i < 17) begin
        i <= i + 1;
    end
    else begin
        i <= 0;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        done_r <= 0;
    end
    else if (i == 16) begin
        done_r <= 1;
    end
    else if (i == 17) begin
        done_r <= 0;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        areg <= 0;
        breg <= 0;
        yout_r <= 0;
    end
    else if (start) begin
        areg <= ain;
        breg <= bin;
        yout_r <= 0;
    end
    else begin
        if (i > 0) begin
            if (breg[0]) begin
                yout_r <= yout_r + areg;
            end
            breg <= breg >> 1;
            areg <= areg << 1;
        end
    end
end

assign yout = yout_r;
assign done = done_r;

endmodule
